@UI.headerInfo: { typeName: 'Vendor', typeNamePlural: 'Vendors',
  title: { type: #STANDARD, value: 'Vendor' } }
define view entity ZC_VendorList as projection on ZI_Vendor {
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  key Lifnr   as Vendor,
  @UI.lineItem: [{ position: 20 }]
      Name1   as VendorName,
  @UI.lineItem: [{ position: 30 }]
      Land1   as Country
}

@AccessControl.authorizationCheck: #CHECK
define view ZI_VendorInvoice as select from acdoca {
  key rbukrs as CompanyCode,
  key belnr  as Document,
      hsl    as Amount
}

" DCL access control object (separate file)
define role ZR_VendorInvoice {
  grant select on ZI_VendorInvoice
    where ( CompanyCode ) =
      aspect pfcg_auth( f_bkpf_buk, bukrs, actvt = '03' );
}

" CDS with correct OData setup
@OData.entityType.name: 'SalesOrderType'
define view ZC_SalesOrder as projection on ZI_SalesOrder {
  key SalesOrder,
      CustomerName,
      NetValue,
      _Items  " expose association
}

" Service Definition: explicitly expose entity + association
define service ZSD_SalesOrder {
  expose ZC_SalesOrder as SalesOrder;
  expose ZC_SalesOrderItem as SalesOrderItem;
}
